mapper.select:
SELECT *
FROM todo_item
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted = FALSE

mapper.update:
UPDATE todo_item
SET deleted = TRUE,
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

mapper.select:
SELECT *
FROM todo_item
WHERE user_id = #{userId}
  AND deleted = FALSE
ORDER BY updated_at DESC
LIMIT #{limit}
